# ---------------------------------------------------------
# Bildverarbeitung
# ---------------------------------------------------------
def normalize_to_srgb(image: Image.Image) -> Image.Image:
    icc = image.info.get("icc_profile")
    if not icc:
        return image
    try:
        input_profile = ImageCms.ImageCmsProfile(io.BytesIO(icc))
        srgb_profile = ImageCms.createProfile("sRGB")
        mode = "RGBA" if image.mode == "RGBA" else "RGB"
        return ImageCms.profileToProfile(image, input_profile, srgb_profile, outputMode=mode)
    except Exception:
        return image


def crop_to_content(img: Image.Image, padding: int = 4) -> Image.Image:
    arr = np.array(img)
    alpha = arr[:, :, 3]
    ys, xs = np.where(alpha > 10)
    if len(xs) == 0:
        return img
    x0, x1 = max(xs.min() - padding, 0), min(xs.max() + padding, img.width)
    y0, y1 = max(ys.min() - padding, 0), min(ys.max() + padding, img.height)
    return img.crop((x0, y0, x1, y1))


ALPHA_FLOOR = 8  # out of 255 — alpha below this is treated as fully transparent
# when unpremultiplying, to avoid amplifying resample "ringing" into visible
# white/color fringing at edges (dividing by a near-zero alpha blows up tiny
# RGB overshoot from BICUBIC/LANCZOS into full-strength color).


def _unpremultiply(r_arr):
    """Shared safe-unpremultiply step used by both resize and rotate below."""
    r_alpha = r_arr[:, :, 3:4]
    low_alpha_mask = r_alpha < ALPHA_FLOOR
    r_alpha_safe = np.where(low_alpha_mask, 255.0, r_alpha)
    unpremult_rgb = (r_arr[:, :, :3] / (r_alpha_safe / 255.0)).clip(0, 255)
    # Anywhere alpha is below the floor, zero the RGB too so no amplified
    # color can survive — treat as fully transparent instead of dividing.
    unpremult_rgb = np.where(low_alpha_mask, 0, unpremult_rgb)
    out_alpha = np.where(low_alpha_mask, 0, r_alpha)
    return np.concatenate([unpremult_rgb, out_alpha], axis=2).astype(np.uint8)


def resize_premultiplied(img, size, resample=Image.Resampling.LANCZOS):
    """Resize RGBA image using premultiplied alpha. Prevents hidden color data
    behind transparent pixels from bleeding into edges as a light/dark halo
    during interpolation (a common issue with plain PIL resize on RGBA)."""
    arr = np.array(img.convert("RGBA")).astype(np.float32)
    rgb = arr[:, :, :3]
    alpha = arr[:, :, 3:4] / 255.0
    premult = rgb * alpha
    premult_img = Image.fromarray(
        np.concatenate([premult, arr[:, :, 3:4]], axis=2).astype(np.uint8), "RGBA"
    )
    resized = premult_img.resize(size, resample)
    r_arr = np.array(resized).astype(np.float32)
    out = _unpremultiply(r_arr)
    return Image.fromarray(out, "RGBA")


def rotate_premultiplied(img, angle, resample=Image.Resampling.BICUBIC):
    """Same premultiplied-alpha approach, applied to rotation."""
    arr = np.array(img.convert("RGBA")).astype(np.float32)
    rgb = arr[:, :, :3]
    alpha = arr[:, :, 3:4] / 255.0
    premult = rgb * alpha
    premult_img = Image.fromarray(
        np.concatenate([premult, arr[:, :, 3:4]], axis=2).astype(np.uint8), "RGBA"
    )
    rotated = premult_img.rotate(angle, expand=True, resample=resample)
    r_arr = np.array(rotated).astype(np.float32)
    out = _unpremultiply(r_arr)
    return Image.fromarray(out, "RGBA")


def place_motif_on_canvas(canvas, motif, slot, canvas_size=CANVAS_SIZE):
    target_dim = slot["width"]
    longer_side = max(motif.width, motif.height)
    scale = target_dim / longer_side
    target_w = int(motif.width * scale)
    target_h = int(motif.height * scale)
    resized = resize_premultiplied(motif, (target_w, target_h), Image.Resampling.LANCZOS)
    rotated = rotate_premultiplied(resized, slot["rotation"], resample=Image.Resampling.BICUBIC)
    rw, rh = rotated.size
    cx, cy = slot["x"], slot["y"]
    paste_x = cx - rw // 2
    paste_y = cy - rh // 2
    canvas.paste(rotated, (paste_x, paste_y), rotated)
    offsets = []
    if paste_x < 0: offsets.append((canvas_size, 0))
    if paste_x + rw > canvas_size: offsets.append((-canvas_size, 0))
    if paste_y < 0: offsets.append((0, canvas_size))
    if paste_y + rh > canvas_size: offsets.append((0, -canvas_size))
    if paste_x < 0 and paste_y < 0: offsets.append((canvas_size, canvas_size))
    if paste_x + rw > canvas_size and paste_y < 0: offsets.append((-canvas_size, canvas_size))
    if paste_x < 0 and paste_y + rh > canvas_size: offsets.append((canvas_size, -canvas_size))
    if paste_x + rw > canvas_size and paste_y + rh > canvas_size: offsets.append((-canvas_size, -canvas_size))
    for dx, dy in offsets:
        canvas.paste(rotated, (paste_x + dx, paste_y + dy), rotated)
    return canvas


def render_template_schematic(template, sample_motif, size=260, canvas_size=CANVAS_SIZE):
    """Real preview: places a sample motif on all slots so you can
    actually see the template layout, not just empty circles."""
    canvas = Image.new("RGBA", (canvas_size, canvas_size), (0, 0, 0, 0))
    for slot in template["main"] + template["secondary"]:
        canvas = place_motif_on_canvas(canvas, sample_motif, slot, canvas_size)
    bg = Image.new("RGBA", canvas.size, (250, 250, 250, 255))
    bg.paste(canvas, (0, 0), canvas)
    return bg.resize((size, size), Image.Resampling.LANCZOS)


def make_sample_motif(size=300):
    """Generates a simple, generic placeholder motif (leaf shape) for the preview."""
    img = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    draw = ImageDraw.Draw(img)
    draw.ellipse([size*0.2, size*0.1, size*0.8, size*0.9], fill=(162, 181, 162, 255))
    draw.ellipse([size*0.35, size*0.3, size*0.65, size*0.6], fill=(250, 250, 250, 255))
    return img


