def clean_edge_fringe(img, erode_px=1):
    """Removes white/light color fringing baked into semi-transparent edge
    pixels (common anti-aliasing artifact from art drawn on a white canvas)
    by eroding the alpha mask slightly and smoothing the new edge."""
    from scipy import ndimage
    arr = np.array(img.convert("RGBA")).astype(np.float32)
    alpha = arr[:, :, 3]
    mask = alpha > 10
    eroded_mask = ndimage.binary_erosion(mask, iterations=erode_px)
    new_alpha = np.where(eroded_mask, alpha, 0)
    new_alpha = ndimage.gaussian_filter(new_alpha, sigma=0.5)
    arr[:, :, 3] = new_alpha
    return Image.fromarray(arr.astype(np.uint8), "RGBA")


def load_motifs_batch(files):
    motifs = []
    if not files:
        return motifs
    for f in files:
        img = Image.open(f).convert("RGBA")
        img = normalize_to_srgb(img)
        img = clean_edge_fringe(img, erode_px=1)
        motifs.append(img)
    return motifs

